import connectDB from '../../../lib/mongodb';
import Donor from '../../../lib/models/Donor';

export default async function handler(req, res) {
    await connectDB();

    const { id, key } = req.query;

    if (key !== process.env.ADMIN_SECRET) {
        return res.status(401).send('Unauthorized');
    }

    const donor = await Donor.findById(id);

    if (!donor) {
        return res.status(404).send('Donor not found');
    }

    const html = `
  <!DOCTYPE html>
  <html>
  <head>
    <title>Blood Donation Certificate</title>

    <style>
      body{
        margin:0;
        padding:40px;
        background:#111;
        font-family:Arial,sans-serif;
      }

      .certificate{
        max-width:900px;
        margin:auto;
        background:#fff;
        padding:60px;
        border:12px solid #F5C800;
        position:relative;
        overflow:hidden;
        }

        .watermark{
        position:absolute;
        inset:0;
        display:flex;
        align-items:center;
        justify-content:center;
        pointer-events:none;
        opacity:0.05;
        z-index:0;
        }

        .watermark img{
        width:500px;
        height:500px;
        object-fit:contain;
        }

        .content,
        .logo,
        .title,
        .subtitle,
        .footer{
        position:relative;
        z-index:2;
        }

      .logo{
        text-align:center;
        margin-bottom:20px;
      }

      .logo img{
        width:100px;
        height:100px;
        border-radius:50%;
      }

      .title{
        text-align:center;
        font-size:48px;
        font-weight:bold;
        color:#CC2200;
        margin-bottom:10px;
      }

      .subtitle{
        text-align:center;
        color:#666;
        letter-spacing:3px;
        margin-bottom:50px;
      }

      .content{
        text-align:center;
      }

      .content h2{
        font-size:42px;
        color:#111;
        margin:20px 0;
      }

      .content p{
        font-size:20px;
        color:#444;
        line-height:1.8;
      }

      .blood{
        display:inline-block;
        margin-top:20px;
        background:#CC2200;
        color:#fff;
        padding:10px 24px;
        border-radius:30px;
        font-size:22px;
        font-weight:bold;
      }

      .footer{
        margin-top:70px;
        display:flex;
        justify-content:space-between;
        align-items:center;
      }

      .sign{
        text-align:center;
      }

      .line{
        width:220px;
        border-top:2px solid #111;
        margin-bottom:10px;
      }

      .print-btn{
        position:fixed;
        top:20px;
        right:20px;
        background:#F5C800;
        border:none;
        padding:12px 20px;
        cursor:pointer;
        font-weight:bold;
      }

      @media print{
        .print-btn{
          display:none;
        }

        body{
          background:#fff;
          padding:0;
        }

        .certificate{
          border-width:8px;
        }

        .certificate::before{
  content:'';
  position:absolute;
  inset:0;
  background:
    radial-gradient(circle at top left, rgba(245,200,0,0.08), transparent 35%),
    radial-gradient(circle at bottom right, rgba(204,34,0,0.06), transparent 35%);
  z-index:0;
}

.watermark { z-index:0; }
.certificate::before { z-index:0; }
.content { z-index:2; }
      }
    </style>
  </head>

  <body>

    <button class="print-btn" onclick="window.print()">
      Print Certificate
    </button>

    <div class="certificate">
    <div class="watermark">
  <img src="data:image/png;base64," />
</div>

      <div class="logo">
        <img src="data:image/png;base64," />
      </div>

      <div class="title">
        Certificate of Appreciation
      </div>

      <div class="subtitle">
        UNITED KETTINAKAM
      </div>

      <div class="content">
        <p>This certificate is proudly presented to</p>

        <h2>${donor.name}</h2>

        <p>
          In recognition of the valuable contribution and willingness
          to donate blood for the community and humanity.
        </p>

        <div class="blood">
          Blood Group: ${donor.bloodGroup}
        </div>
      </div>

      <div class="footer">
        <div class="sign">
          <div class="line"></div>
          Donor Signature
        </div>

        <div class="sign">
          <div class="line"></div>
          United Kettinakam
        </div>
      </div>

    </div>

  </body>
  </html>
  `;

    res.setHeader('Content-Type', 'text/html');
    res.send(html);
}